from dataclasses import dataclass
from typing import Optional

@dataclass
class Session:
    session_id: str
    resolved: bool
    escalated: bool
    user_rating: Optional[int]  # 1-5
    duration_seconds: float

def task_completion_rate(sessions: list[Session]) -> dict:
    total = len(sessions)
    if total == 0:
        return {}
    completed = sum(1 for s in sessions if s.resolved and not s.escalated)
    escalated = sum(1 for s in sessions if s.escalated)
    return {
        'tcr': completed / total,
        'escalation_rate': escalated / total,
        'abandonment_rate': (total - completed - escalated) / total,
        'n': total,
    }

import time, statistics
from dataclasses import dataclass, field

@dataclass
class LatencyRecord:
    ttft_ms: float
    total_ms: float
    output_tokens: int

    @property
    def tps(self) -> float:
        gen_time_s = (self.total_ms - self.ttft_ms) / 1000
        return self.output_tokens / gen_time_s if gen_time_s > 0 else 0

def latency_report(records: list[LatencyRecord]) -> dict:
    ttfts = sorted(r.ttft_ms for r in records)
    tps_vals = sorted(r.tps for r in records)
    def pct(vals, p): return vals[int(len(vals) * p / 100)]
    return {
        'ttft_p50_ms': pct(ttfts, 50),
        'ttft_p95_ms': pct(ttfts, 95),
        'ttft_p99_ms': pct(ttfts, 99),
        'tps_p50':     pct(tps_vals, 50),
        'tps_p10':     pct(tps_vals, 10),  # worst decile
    }

def cost_per_resolved_task(
    cost_per_convo: float,
    task_completion_rate: float,
) -> float:
    """Cost to produce one resolved user task at current TCR."""
    if task_completion_rate <= 0:
        return float('inf')
    return cost_per_convo / task_completion_rate

# Example: $0.04 per conversation, 70% TCR vs $0.01 per conversation, 30% TCR
print(f'High-quality model: ${cost_per_resolved_task(0.04, 0.70):.4f}/task')  # $0.0571
print(f'Budget model:       ${cost_per_resolved_task(0.01, 0.30):.4f}/task')  # $0.0333
# Budget model wins on unit economics here despite 30% TCR

from collections import Counter
import re

def escalation_topic_analysis(
    escalated_queries: list[str],
    total_queries: int,
) -> dict:
    # Simple keyword clustering — replace with embedding-based clustering in production
    topic_keywords = {
        'billing': ['invoice', 'charge', 'refund', 'payment', 'subscription'],
        'technical': ['error', 'bug', 'crash', 'not working', 'broken'],
        'account': ['password', 'login', 'access', 'locked', '2fa'],
        'policy': ['return', 'cancel', 'privacy', 'gdpr', 'delete'],
    }
    topic_counts: Counter = Counter()
    for q in escalated_queries:
        q_lower = q.lower()
        for topic, keywords in topic_keywords.items():
            if any(kw in q_lower for kw in keywords):
                topic_counts[topic] += 1
                break
        else:
            topic_counts['uncategorised'] += 1
    rate = len(escalated_queries) / total_queries if total_queries else 0
    return {
        'escalation_rate': rate,
        'top_topics': topic_counts.most_common(5),
        'n_escalated': len(escalated_queries),
    }
